    test("Sample (1)", async () => {
        const server = mockServerPool.createServer();
        const client = new PolytomicClient({
            maxRetries: 0,
            token: "test",
            version: "test",
            environment: server.baseUrl,
        });

        const rawResponseBody = {
            data: {
                records: [{ "enricher-uuid": { name: "James" }, "model-uuid": { name: "Jim" } }],
                warnings: ["Enrichment failed for 4 records: you have ran out of credits"],
            },
            job: {
                error: "error message",
                job_id: "248df4b7-aa70-47b8-a036-33ac447e668d",
                result: { key: "value" },
                status: "created",
                type: "createmodel",
            },
        };

        server
            .mockEndpoint()
            .get("/api/models/248df4b7-aa70-47b8-a036-33ac447e668d/sample")
            .respondWith()
            .statusCode(200)
            .jsonBody(rawResponseBody)
            .build();

        const response = await client.models.sample("248df4b7-aa70-47b8-a036-33ac447e668d", {
            async: true,
        });
        expect(response).toEqual({
            data: {
                records: [
                    {
                        "enricher-uuid": {
                            name: "James",
                        },
                        "model-uuid": {
                            name: "Jim",
                        },
                    },
                ],
                warnings: ["Enrichment failed for 4 records: you have ran out of credits"],
            },
            job: {
                error: "error message",
                job_id: "248df4b7-aa70-47b8-a036-33ac447e668d",
                result: {
                    key: "value",
                },
                status: "created",
                type: "createmodel",
            },
        });
    });

